    ('– EXISION OF REGIONAL DEEP LYMPH NODES LYMPHADENECTOMY', '– EXISION OF REGIONAL DEEP LYMPH NODES LYMPHADENECTOMY', 'SP-RAD')
),
filtered AS (
    SELECT s.name_ar, s.name_en, s.spec_code
    FROM src s
    WHERE NOT EXISTS (
        SELECT 1
        FROM medical_services ms
        WHERE ms.deleted = FALSE
          AND LOWER(TRIM(ms.name_ar)) = LOWER(TRIM(s.name_ar))
    )
),
numbered AS (
    SELECT
        f.name_ar,
        f.name_en,
        f.spec_code,
        ROW_NUMBER() OVER (ORDER BY f.spec_code, f.name_ar) AS rn
    FROM filtered f
)
INSERT INTO medical_services (code, name, name_ar, name_en, status, specialty_id, deleted)
SELECT
    'SRV-XLS-' || SUBSTRING(
        MD5(
            COALESCE(TRIM(n.spec_code), '') || '|' ||
            COALESCE(TRIM(n.name_ar), '') || '|' ||
            COALESCE(TRIM(n.name_en), '')
        )
        FROM 1 FOR 16
    ) AS code,
    COALESCE(NULLIF(TRIM(n.name_ar), ''), NULLIF(TRIM(n.name_en), ''), 'UNNAMED SERVICE') AS name,
    n.name_ar,
    n.name_en,
    'ACTIVE' AS status,
    (SELECT id FROM medical_specialties WHERE code = n.spec_code AND deleted = FALSE LIMIT 1) AS specialty_id,
    FALSE
FROM numbered n
WHERE EXISTS (
    SELECT 1
    FROM medical_specialties sp
    WHERE sp.code = n.spec_code AND sp.deleted = FALSE
);
